/* ============================================================
   Whitepaper — The AI-Ready Analytics Stack (vendor-neutral)
   All styles scoped under .wp (no :root / body / * — block-safe).
   Self-contained dark surface; flips to a light, ink-friendly
   palette under @media print so "Save as PDF" yields a clean doc.
   ============================================================ */

.wp {
  /* --- Accent (indigo -> cyan) --- */
  --pink: #8b78ff;
  --orange: #22d3ee;
  --grad: linear-gradient(135deg, #8b78ff 0%, #22d3ee 100%);
  --grad-soft: linear-gradient(135deg, rgba(139,120,255,.16), rgba(34,211,238,.16));
  /* deeper indigo -> teal for gradient-filled surfaces that carry WHITE text (AA-safe) */
  --grad-deep: linear-gradient(135deg, #6a59e0 0%, #0e7490 100%);

  /* --- Supporting accents (diagrams only) --- */
  --blue: #34b9f3;
  --green: #36d399;
  --violet: #9d7bff;

  /* --- Dark canvas palette (self-contained; theme-independent) --- */
  --canvas: #0a0a0c;
  --canvas-2: #0e0e12;
  --surface: #141419;
  --surface-2: #1a1a21;
  --surface-3: #20202a;
  --line: rgba(255,255,255,.08);
  --line-2: rgba(255,255,255,.14);
  --ink: #f4f4f7;
  --ink-soft: #c6c6d0;
  --ink-mute: #8a8a96;

  --shadow-sm: 0 1px 2px rgba(0,0,0,.4);
  --shadow-md: 0 10px 30px rgba(0,0,0,.45);
  --shadow-glow: 0 0 0 1px rgba(139,120,255,.18), 0 18px 50px rgba(139,120,255,.10);

  --radius: 16px;
  --radius-sm: 11px;
  --radius-lg: 22px;
  --maxw: 1080px;

  --font: var(--font-stack-primary, 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif);

  position: relative;
  width: 100%;
  min-height: 100%;
  margin: 0;
  background: var(--canvas);
  color: var(--ink);
  font-family: var(--font);
  font-size: 16px;
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  overflow-x: hidden;
}

.wp *,
.wp *::before,
.wp *::after { box-sizing: border-box; }

/* Ambient gradient field behind everything */
.wp .wp-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background:
    radial-gradient(1100px 620px at 78% -8%, rgba(34,211,238,.16), transparent 60%),
    radial-gradient(980px 560px at 8% 4%, rgba(139,120,255,.18), transparent 58%),
    radial-gradient(900px 900px at 50% 120%, rgba(52,185,243,.08), transparent 60%);
}
.wp .wp-grid {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  opacity: .5;
  background-image:
    linear-gradient(rgba(255,255,255,.025) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,.025) 1px, transparent 1px);
  background-size: 64px 64px;
  mask-image: linear-gradient(180deg, #000 0%, transparent 30%);
  -webkit-mask-image: linear-gradient(180deg, #000 0%, transparent 30%);
}

.wp .wp-shell {
  position: relative;
  z-index: 1;
  max-width: var(--maxw);
  margin: 0 auto;
  padding: 0 28px 96px;
}

/* ---------- Sticky top bar ---------- */
.wp .wp-topbar {
  position: sticky;
  top: 0;
  z-index: 30;
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 12px clamp(16px, 4vw, 40px);
  background: color-mix(in srgb, var(--canvas) 78%, transparent);
  backdrop-filter: blur(14px) saturate(140%);
  -webkit-backdrop-filter: blur(14px) saturate(140%);
  border-bottom: 1px solid var(--line);
}
.wp .wp-brand { display: flex; align-items: center; gap: 11px; min-width: 0; }
.wp .wp-mark {
  width: 26px; height: 26px; border-radius: 8px; flex: none;
  background: var(--grad);
  box-shadow: 0 4px 14px rgba(139,120,255,.4);
  position: relative;
}
.wp .wp-mark::after {
  content: ""; position: absolute; inset: 6px;
  border-radius: 4px;
  background: var(--canvas);
  opacity: .92;
  clip-path: polygon(0 100%, 42% 0, 58% 0, 100% 100%, 72% 100%, 50% 44%, 28% 100%);
}
.wp .wp-brand b {
  font-size: 12px; font-weight: 800; letter-spacing: .16em;
  text-transform: uppercase; color: var(--ink);
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.wp .wp-brand b span { color: var(--ink-mute); font-weight: 700; }
.wp .wp-actions { margin-left: auto; display: flex; align-items: center; gap: 10px; }
.wp .wp-pdf {
  display: inline-flex; align-items: center; gap: 8px;
  font: 700 12.5px/1 var(--font); letter-spacing: .02em;
  color: var(--ink);
  padding: 9px 15px; border-radius: 999px;
  border: 1px solid var(--line-2);
  background: var(--surface-2);
  cursor: pointer; transition: transform .15s ease, border-color .15s ease, background .15s ease;
}
.wp .wp-pdf:hover { transform: translateY(-1px); border-color: rgba(34,211,238,.6); background: var(--surface-3); }
.wp .wp-pdf:focus-visible { outline: 2px solid var(--orange); outline-offset: 2px; }
.wp .wp-pdf svg { width: 15px; height: 15px; }

/* ---------- Generic primitives ---------- */
.wp .eyebrow {
  display: inline-flex; align-items: center; gap: 9px;
  font: 800 11px/1 var(--font); letter-spacing: .2em; text-transform: uppercase;
  color: var(--ink-soft);
  margin: 0 0 16px;
}
.wp .eyebrow::before {
  content: ""; width: 20px; height: 2px; border-radius: 2px;
  background: var(--grad);
}
.wp .eyebrow.center { justify-content: center; }

.wp h1, .wp h2, .wp h3, .wp h4 { margin: 0; letter-spacing: -.02em; line-height: 1.12; font-weight: 800; }
.wp p { margin: 0 0 16px; color: var(--ink-soft); }
.wp p:last-child { margin-bottom: 0; }
.wp strong { color: var(--ink); font-weight: 700; }
.wp code { font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace; font-size: .88em; background: var(--surface-3); border: 1px solid var(--line); border-radius: 5px; padding: 1px 6px; color: var(--ink); }
.wp .lead { font-size: 18px; line-height: 1.65; color: var(--ink-soft); }
.wp .grad-text {
  background: var(--grad); -webkit-background-clip: text; background-clip: text;
  -webkit-text-fill-color: transparent; color: transparent;
}
.wp a { color: var(--orange); text-decoration: none; border-bottom: 1px solid rgba(34,211,238,.35); transition: color .15s, border-color .15s; }
.wp a:hover { color: var(--pink); border-color: var(--pink); }
.wp a:focus-visible { outline: 2px solid var(--orange); outline-offset: 3px; border-radius: 3px; }

/* ---------- Section frame ---------- */
.wp .section { padding: 72px 0 8px; scroll-margin-top: 80px; }
.wp .section-head { max-width: 760px; margin-bottom: 34px; }
.wp .section-head.center { margin-left: auto; margin-right: auto; text-align: center; }
.wp .section-title { font-size: clamp(26px, 4.4vw, 40px); color: var(--ink); }
.wp .section-sub { margin-top: 16px; font-size: 17px; line-height: 1.65; color: var(--ink-soft); }
.wp .kicker-num {
  font: 800 13px/1 var(--font); letter-spacing: .04em;
  color: var(--orange); margin-right: 4px;
}

/* ---------- HERO ---------- */
.wp .hero { position: relative; padding: clamp(56px, 9vw, 104px) 0 56px; }
.wp .hero-eyebrow {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 7px 14px; border-radius: 999px;
  border: 1px solid var(--line-2);
  background: var(--surface-2);
  font: 800 11px/1 var(--font); letter-spacing: .18em; text-transform: uppercase;
  color: var(--ink-soft); margin-bottom: 26px;
}
.wp .hero-eyebrow .dot { width: 7px; height: 7px; border-radius: 50%; background: var(--grad); box-shadow: 0 0 10px rgba(34,211,238,.8); }
.wp .hero-title {
  font-size: clamp(38px, 7.6vw, 76px);
  line-height: 1.02; letter-spacing: -.035em; font-weight: 800; color: var(--ink);
  margin: 0 0 24px; max-width: 16ch;
}
.wp .hero-title .grad-text { letter-spacing: -.035em; }
.wp .hero-sub { font-size: clamp(17px, 2.4vw, 22px); line-height: 1.5; color: var(--ink-soft); max-width: 60ch; margin: 0 0 34px; }
.wp .hero-meta { display: flex; flex-wrap: wrap; align-items: center; gap: 12px 22px; }
.wp .hero-byline { display: flex; align-items: center; gap: 11px; }
.wp .hero-avatar {
  width: 38px; height: 38px; border-radius: 50%; flex: none;
  background: var(--grad-deep); color: #fff;
  display: grid; place-items: center; font: 800 14px/1 var(--font); letter-spacing: .02em;
  box-shadow: 0 6px 18px rgba(139,120,255,.4);
}
.wp .hero-byline .who { font: 700 14px/1.3 var(--font); color: var(--ink); }
.wp .hero-byline .what { font: 600 12px/1.3 var(--font); color: var(--ink-mute); }
.wp .hero-dot { width: 4px; height: 4px; border-radius: 50%; background: var(--line-2); }
.wp .hero-tag { font: 600 12.5px/1 var(--font); color: var(--ink-mute); }

/* hero pillar strip */
.wp .pillars {
  margin-top: 50px;
  display: grid; grid-template-columns: repeat(3, 1fr); gap: 14px;
}
.wp .pillar {
  position: relative; overflow: hidden;
  padding: 20px 20px 22px; border-radius: var(--radius);
  background: linear-gradient(180deg, var(--surface), var(--canvas-2));
  border: 1px solid var(--line);
}
.wp .pillar::before { content: ""; position: absolute; left: 0; top: 0; height: 3px; width: 100%; background: var(--grad); opacity: .9; }
.wp .pillar .pk { font: 800 11px/1 var(--font); letter-spacing: .16em; text-transform: uppercase; color: var(--ink-mute); }
.wp .pillar .pt { margin-top: 10px; font: 800 19px/1.2 var(--font); color: var(--ink); letter-spacing: -.01em; }
.wp .pillar .pd { margin-top: 7px; font: 500 13.5px/1.5 var(--font); color: var(--ink-soft); }

/* ---------- Stat band ---------- */
.wp .statband {
  margin-top: 30px;
  display: grid; grid-template-columns: repeat(4, 1fr); gap: 1px;
  background: var(--line); border: 1px solid var(--line); border-radius: var(--radius); overflow: hidden;
}
.wp .stat { background: var(--surface); padding: 22px 20px; }
.wp .stat .v { font: 800 clamp(26px, 3.4vw, 34px)/1 var(--font); letter-spacing: -.02em; color: var(--ink); font-variant-numeric: tabular-nums; }
.wp .stat .v .grad-text { background: var(--grad); -webkit-background-clip: text; background-clip: text; -webkit-text-fill-color: transparent; }
.wp .stat .l { margin-top: 9px; font: 600 12.5px/1.4 var(--font); color: var(--ink-mute); }
.wp .stat .src { margin-top: 4px; font: 600 10.5px/1.3 var(--font); color: var(--ink-mute); opacity: .8; }

/* ---------- Feature cards ---------- */
.wp .cards { display: grid; gap: 16px; }
.wp .cards.c3 { grid-template-columns: repeat(3, 1fr); }
.wp .cards.c2 { grid-template-columns: repeat(2, 1fr); }
.wp .card {
  position: relative;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: var(--radius);
  padding: 24px 22px;
  transition: transform .18s ease, border-color .18s ease, box-shadow .18s ease;
}
.wp .card:hover { transform: translateY(-3px); border-color: var(--line-2); box-shadow: var(--shadow-md); }
.wp .ic {
  width: 44px; height: 44px; border-radius: 12px; display: grid; place-items: center;
  background: var(--grad-soft); border: 1px solid rgba(34,211,238,.28);
  margin-bottom: 16px;
}
.wp .ic svg { width: 22px; height: 22px; stroke: var(--orange); fill: none; stroke-width: 1.7; }
.wp .card h3 { font-size: 17px; color: var(--ink); margin-bottom: 9px; }
.wp .card p { font-size: 14px; line-height: 1.6; color: var(--ink-soft); margin: 0; }
.wp .card .meta { margin-top: 14px; font: 700 11px/1 var(--font); letter-spacing: .12em; text-transform: uppercase; color: var(--ink-mute); }

/* dense list inside prose */
.wp .ticks { list-style: none; margin: 6px 0 0; padding: 0; display: grid; gap: 11px; }
.wp .ticks li { position: relative; padding-left: 30px; font-size: 14.5px; line-height: 1.55; color: var(--ink-soft); }
.wp .ticks li::before {
  content: ""; position: absolute; left: 0; top: 3px;
  width: 18px; height: 18px; border-radius: 50%;
  background: var(--grad-soft); border: 1px solid rgba(34,211,238,.4);
}
.wp .ticks li::after {
  content: ""; position: absolute; left: 6px; top: 8px;
  width: 6px; height: 3px; border-left: 2px solid var(--orange); border-bottom: 2px solid var(--orange);
  transform: rotate(-45deg);
}
.wp .ticks li b { color: var(--ink); }

/* ---------- Split text block ---------- */
.wp .split { display: grid; grid-template-columns: 1.05fr .95fr; gap: 40px; align-items: start; }
.wp .prose h3 { font-size: 19px; color: var(--ink); margin: 26px 0 12px; }
.wp .prose h3:first-child { margin-top: 0; }
.wp .prose p { font-size: 15px; }

/* ---------- Diagram frame ---------- */
.wp .figure {
  margin: 8px 0 0; padding: 26px 24px 18px;
  background: linear-gradient(180deg, var(--surface), var(--canvas-2));
  border: 1px solid var(--line); border-radius: var(--radius-lg);
  box-shadow: var(--shadow-md);
}
.wp .figure svg { display: block; width: 100%; height: auto; }
.wp .figure figcaption { margin-top: 16px; font: 600 12.5px/1.5 var(--font); color: var(--ink-mute); text-align: center; }
.wp .figure figcaption b { color: var(--ink-soft); }

/* diagram node legend */
.wp .legend { display: flex; flex-wrap: wrap; gap: 8px 18px; justify-content: center; margin-top: 14px; }
.wp .legend span { display: inline-flex; align-items: center; gap: 7px; font: 600 12px/1 var(--font); color: var(--ink-mute); }
.wp .legend i { width: 10px; height: 10px; border-radius: 3px; display: inline-block; }

/* ---------- Callout / pull ---------- */
.wp .callout {
  position: relative; margin: 8px 0 0; padding: 26px 28px 26px 30px;
  border-radius: var(--radius);
  background: var(--grad-soft);
  border: 1px solid rgba(34,211,238,.28);
}
.wp .callout::before { content: ""; position: absolute; left: 0; top: 14px; bottom: 14px; width: 3px; border-radius: 3px; background: var(--grad); }
.wp .callout .ql { font: 800 11px/1 var(--font); letter-spacing: .16em; text-transform: uppercase; color: var(--orange); margin-bottom: 12px; }
.wp .callout p { color: var(--ink); font-size: 18px; line-height: 1.55; margin: 0; font-weight: 500; }
.wp .callout.quote p { font-size: 21px; font-weight: 600; letter-spacing: -.01em; }
.wp .callout cite { display: block; margin-top: 14px; font-style: normal; font: 600 13px/1.4 var(--font); color: var(--ink-mute); }

/* ---------- Comparison table ---------- */
.wp .tbl-wrap { overflow-x: auto; -webkit-overflow-scrolling: touch; border: 1px solid var(--line); border-radius: var(--radius); }
.wp table.cmp { width: 100%; border-collapse: collapse; font: 500 14px/1.5 var(--font); min-width: 640px; }
.wp table.cmp thead th { position: sticky; top: 0; background: var(--surface-2); text-align: left; font: 800 11px/1.2 var(--font); letter-spacing: .1em; text-transform: uppercase; color: var(--ink-mute); padding: 15px 18px; border-bottom: 1px solid var(--line-2); }
.wp table.cmp thead th.hl { color: var(--orange); }
.wp table.cmp tbody td, .wp table.cmp tbody th { padding: 15px 18px; border-top: 1px solid var(--line); color: var(--ink-soft); vertical-align: top; }
.wp table.cmp tbody th[scope="row"] { color: var(--ink); font-weight: 700; text-align: left; }
.wp table.cmp tbody td.hl { color: var(--ink); }
.wp table.cmp tbody tr:hover td { background: rgba(255,255,255,.02); }
.wp table.cmp .zcell { display: inline-flex; align-items: baseline; gap: 8px; }
.wp table.cmp .zcell::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: var(--grad); align-self: center; flex: none; }

/* ---------- CTA ---------- */
.wp .cta {
  position: relative; overflow: hidden;
  margin-top: 30px; padding: clamp(36px, 6vw, 64px) clamp(28px, 6vw, 60px);
  border-radius: var(--radius-lg);
  background: linear-gradient(135deg, rgba(139,120,255,.16), rgba(34,211,238,.10)), var(--surface);
  border: 1px solid rgba(34,211,238,.3);
  box-shadow: var(--shadow-glow);
  text-align: center;
}
.wp .cta::before { content: ""; position: absolute; inset: 0; background: radial-gradient(600px 300px at 50% -20%, rgba(34,211,238,.22), transparent 70%); pointer-events: none; }
.wp .cta h2 { position: relative; font-size: clamp(26px, 4.6vw, 40px); color: var(--ink); margin-bottom: 16px; }
.wp .cta p { position: relative; max-width: 58ch; margin: 0 auto 28px; font-size: 17px; color: var(--ink-soft); }
.wp .cta-btns { position: relative; display: flex; flex-wrap: wrap; gap: 14px; justify-content: center; }
.wp .btn {
  display: inline-flex; align-items: center; gap: 9px;
  font: 700 15px/1 var(--font); letter-spacing: .01em;
  padding: 15px 26px; border-radius: 999px; cursor: pointer; border: 1px solid transparent;
  transition: transform .15s ease, box-shadow .15s ease, background .15s, border-color .15s;
}
.wp .btn svg { width: 17px; height: 17px; }
.wp .btn-primary { background: var(--grad); color: #15090f; box-shadow: 0 10px 26px rgba(139,120,255,.38); border: none; }
.wp .btn-primary:hover { transform: translateY(-2px); box-shadow: 0 16px 38px rgba(139,120,255,.5); }
.wp .btn-ghost { background: transparent; color: var(--ink); border: 1px solid var(--line-2); }
.wp .btn-ghost:hover { transform: translateY(-2px); border-color: rgba(34,211,238,.6); background: var(--surface-2); }
.wp .btn:focus-visible { outline: 2px solid var(--orange); outline-offset: 3px; }

/* ---------- TOC chips ---------- */
.wp .toc { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 30px; }
.wp .toc a {
  border: none; font: 700 12.5px/1 var(--font); color: var(--ink-soft);
  padding: 9px 14px; border-radius: 999px; background: var(--surface-2);
  border: 1px solid var(--line); transition: border-color .15s, color .15s, transform .15s;
}
.wp .toc a:hover { color: var(--ink); border-color: rgba(34,211,238,.5); transform: translateY(-1px); }
.wp .toc a span { color: var(--orange); margin-right: 6px; font-weight: 800; }

/* ---------- Footer ---------- */
.wp .wp-foot { margin-top: 80px; padding-top: 28px; border-top: 1px solid var(--line); }
.wp .wp-foot .disc { font: 500 12.5px/1.7 var(--font); color: var(--ink-mute); max-width: 80ch; }
.wp .wp-foot .disc b { color: var(--ink-soft); }
.wp .wp-foot .row { display: flex; flex-wrap: wrap; align-items: center; gap: 10px 18px; margin-top: 18px; }
.wp .wp-foot .row .c { font: 600 12px/1 var(--font); color: var(--ink-mute); }
.wp .refs { margin-top: 22px; font: 500 11.5px/1.7 var(--font); color: var(--ink-mute); }
.wp .refs b { color: var(--ink-soft); display: block; margin-bottom: 6px; letter-spacing: .08em; text-transform: uppercase; font-size: 10.5px; }

/* ---------- Flow diagram (HTML nodes + chevrons; reflows) ---------- */
.wp .flow { display: flex; flex-wrap: wrap; align-items: stretch; gap: 10px; }
.wp .flow-node {
  flex: 1 1 130px; min-width: 120px;
  background: var(--surface-2); border: 1px solid var(--line-2);
  border-radius: 14px; padding: 16px 14px; text-align: center;
  display: flex; flex-direction: column; justify-content: center; gap: 6px;
}
.wp .flow-node.accent { background: var(--grad-deep); border-color: transparent; box-shadow: 0 12px 30px rgba(139,120,255,.28); }
.wp .flow-node.accent .nk { color: #fff; }
.wp .flow-node.accent .nt { color: #fff; }
.wp .flow-node.accent .nd { color: #fff; }
.wp .flow-node .nk { font: 800 9.5px/1 var(--font); letter-spacing: .14em; text-transform: uppercase; color: var(--ink-mute); }
.wp .flow-node .nt { font: 800 14.5px/1.2 var(--font); color: var(--ink); letter-spacing: -.01em; }
.wp .flow-node .nd { font: 500 11.5px/1.45 var(--font); color: var(--ink-soft); }
.wp .flow-node .chips { display: flex; flex-direction: column; gap: 6px; margin-top: 4px; }
.wp .flow-node .chip { font: 700 11px/1 var(--font); padding: 6px 8px; border-radius: 7px; background: rgba(0,0,0,.3); color: #fff; }
.wp .flow-arrow { flex: 0 0 auto; display: flex; align-items: center; color: var(--ink-mute); }
.wp .flow-arrow svg { width: 22px; height: 22px; }
/* A flow inside a narrow split column always stacks (it can't fit horizontally) */
.wp .split .flow { flex-direction: column; }
.wp .split .flow .flow-arrow { align-self: center; transform: rotate(90deg); }

/* Hub / fan (headless) */
.wp .fan { margin-top: 14px; display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; position: relative; }
.wp .fan::before { content: ""; position: absolute; top: -14px; left: 0; right: 0; height: 14px;
  background: linear-gradient(var(--line-2), transparent); -webkit-mask: linear-gradient(#000,transparent); }
.wp .fan .spoke { background: var(--surface-2); border: 1px solid var(--line); border-radius: 12px; padding: 14px 12px; text-align: center; }
.wp .fan .spoke .si { width: 32px; height: 32px; margin: 0 auto 9px; border-radius: 9px; display: grid; place-items: center; background: var(--grad-soft); border: 1px solid rgba(34,211,238,.3); }
.wp .fan .spoke .si svg { width: 17px; height: 17px; stroke: var(--orange); fill: none; stroke-width: 1.7; }
.wp .fan .spoke .st { font: 800 12.5px/1.25 var(--font); color: var(--ink); }
.wp .fan .spoke .sd { margin-top: 5px; font: 500 11px/1.4 var(--font); color: var(--ink-mute); }
.wp .hub {
  text-align: center; padding: 18px; border-radius: var(--radius);
  background: var(--grad-deep); color: #fff; box-shadow: 0 14px 34px rgba(139,120,255,.3);
}
.wp .hub .hk { font: 800 10px/1 var(--font); letter-spacing: .16em; text-transform: uppercase; color: #fff; }
.wp .hub .ht { margin-top: 8px; font: 800 18px/1.2 var(--font); letter-spacing: -.01em; }
.wp .hub .hd { margin-top: 6px; font: 500 12.5px/1.5 var(--font); color: #fff; max-width: 56ch; margin-left: auto; margin-right: auto; }

/* Governance gate strip (MCP section) */
.wp .gate {
  margin-top: 14px; display: flex; flex-wrap: wrap; align-items: center; gap: 10px 14px;
  padding: 14px 18px; border-radius: var(--radius);
  background: var(--surface-2); border: 1px dashed var(--line-2);
}
.wp .gate .gk { font: 800 10px/1 var(--font); letter-spacing: .15em; text-transform: uppercase; color: var(--orange); }
.wp .gate .gp { font: 700 12px/1 var(--font); color: var(--ink-soft); padding: 7px 11px; border-radius: 999px; background: var(--surface-3); border: 1px solid var(--line); }

@media (max-width: 1024px) {
  .wp .flow { flex-direction: column; }
  .wp .flow-arrow { align-self: center; transform: rotate(90deg); }
}

/* ---------- Reveal animation (gated by .js so no-JS shows everything) ---------- */
.wp.js .reveal { opacity: 0; transform: translateY(18px); transition: opacity .6s ease, transform .6s ease; }
.wp.js .reveal.is-in { opacity: 1; transform: none; }

/* ---------- Responsive ---------- */
@media (max-width: 900px) {
  .wp .split { grid-template-columns: 1fr; gap: 26px; }
  .wp .cards.c3 { grid-template-columns: repeat(2, 1fr); }
  .wp #shift .cards.c3, .wp #strategy .cards.c3 { grid-template-columns: 1fr; } /* trios stack instead of 2+1 orphan */
  .wp .pillars { grid-template-columns: 1fr; }
  .wp .statband { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 560px) {
  .wp { font-size: 15px; }
  .wp .wp-shell { padding: 0 18px 72px; }
  .wp .cards.c3, .wp .cards.c2 { grid-template-columns: 1fr; }
  .wp .statband { grid-template-columns: repeat(2, 1fr); }
  .wp .wp-brand b span { display: none; }
  .wp .section { padding: 54px 0 8px; }
}

@media (prefers-reduced-motion: reduce) {
  .wp * { animation: none !important; transition: none !important; }
  .wp .reveal, .wp.js .reveal { opacity: 1 !important; transform: none !important; }
}

/* ---------- Print -> clean light document ---------- */
@media print {
  .wp {
    --canvas: #ffffff; --canvas-2: #ffffff;
    --surface: #ffffff; --surface-2: #f6f7f9; --surface-3: #f0f1f4;
    --line: #e3e5ea; --line-2: #d4d7de;
    --ink: #15151a; --ink-soft: #34343c; --ink-mute: #6b6b75;
    /* darken accent so var(--orange) text (kickers, labels, icon strokes) clears 4.5:1 on white */
    --orange: #4f46e5; --pink: #4f46e5;
    --shadow-md: none; --shadow-glow: none; --shadow-sm: none;
    background: #fff; color: #15151a;
    font-size: 11.5px;
  }
  .wp .wp-bg, .wp .wp-grid, .wp .cta::before, .wp .hero-eyebrow .dot { display: none !important; }
  .wp .wp-topbar { display: none !important; }
  .wp .card, .wp .pillar, .wp .figure, .wp .cta, .wp .callout, .wp .stat, .wp .toc a { box-shadow: none !important; }
  .wp .reveal { opacity: 1 !important; transform: none !important; }
  .wp .section { padding: 22px 0 0; }
  .wp .figure, .wp table.cmp, .wp .cta, .wp .callout, .wp .card, .wp .pillar, .wp .stat, .wp .fan .spoke { page-break-inside: avoid; }
  .wp .section-title { page-break-after: avoid; }
  .wp .hero { padding: 8px 0 24px; }
  .wp a { color: #4f46e5; border: none; }
  .wp .toc { display: none; }
  /* gradient-clipped text -> solid ink-safe color (the hero "AI-Native" word, pull-quotes) */
  .wp .grad-text { background: none !important; -webkit-text-fill-color: #4f46e5 !important; color: #4f46e5 !important; }
  /* flip gradient-filled diagram surfaces to light cards so they stay legible even with
     "Background graphics" disabled in the print dialog */
  .wp .flow-node.accent { background: var(--surface-2) !important; border: 1px solid var(--line-2) !important; }
  .wp .flow-node.accent .nt { color: var(--ink) !important; }
  .wp .flow-node.accent .nk, .wp .flow-node.accent .nd { color: var(--ink-mute) !important; }
  .wp .flow-node .chip { background: var(--surface-3) !important; color: var(--ink) !important; }
  .wp .hub { background: var(--surface-2) !important; }
  .wp .hub .ht { color: var(--ink) !important; }
  .wp .hub .hk, .wp .hub .hd { color: var(--ink-mute) !important; }
  .wp .hero-avatar { background: var(--surface-2) !important; color: var(--ink) !important; border: 1px solid var(--line-2); }
  .wp .btn-primary { background: var(--surface-2) !important; color: var(--ink) !important; border: 1px solid var(--line-2) !important; }
}
